PREFIX ecrm: <http://erlangen-crm.org/current/>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>
SELECT ?work WHERE { ?work ecrm:P9_consists_of ?composition . ?composition ecrm:P14_carried_out_by ?composer . ?composer foaf:name ?composerName . ?composition ecrm:P100_has_time_span ?timeSpan . ?timeSpan ecrm:P115_has_duration ?duration . ?work ecrm:P113_has_location ?venue . FILTER ( ?composerName = 'Beethoven' || ?composerName = 'Schubert' || ?composerName = 'Mendelssohn' ) . FILTER ( ?duration >= '1800' && ?duration <= '1850' ) . FILTER ( ?venue = 'Royal Albert Hall' ) }

PREFIX ecrm: <http://erlangen-crm.org/current/>
PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
SELECT ?work WHERE { ?work efrbroo:R17_created ?expression . ?expression ecrm:P9_consists_of ?instrument . ?instrument a efrbroo:F22_Self-Contained_Expression }

PREFIX foaf: <http://xmlns.com/foaf/0.1/>
PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
SELECT ?work WHERE { ?work efrbroo:R8_consists_of ?instrument . ?instrument foaf:name 'flute' }

PREFIX ecrm: <http://erlangen-crm.org/current/>
PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
SELECT ?concert WHERE { ?concert ecrm:P14_carried_out_by ?violinist . ?concert ecrm:P9_consists_of ?work . ?work efrbroo:R17_created ?composer . }

PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?work WHERE { ?work efrbroo:R17_created <http://data.doremus.org/track/1c4512e0-3c29-3ca6-bd58-69f46b74a5a4> . ?work rdfs:label ?label . FILTER (CONTAINS(STR(?label), 'Piano')) }

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ecrm: <http://erlangen-crm.org/current/>
SELECT ?performance WHERE { ?performance ecrm:P14_carried_out_by ?location . ?location rdfs:label "Abbaye aux Dames de Saintes"@fr }

PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
PREFIX dct: <http://purl.org/dc/terms/>
SELECT ?expression WHERE { ?expression efrbroo:R22_created ?work . ?work dct:creator ?lyricist . }

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
SELECT ?expression WHERE { ?expression efrbroo:U12_has_genre ?genre . ?genre rdfs:label "popular music"@en . }

PREFIX ecrm: <http://erlangen-crm.org/current/>
PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
SELECT ?work WHERE { ?work a efrbroo:F22_Self-Contained_Expression ; ecrm:P14_carried_out_by <http://data.doremus.org/artist/4802a043-23bb-3b8d-a443-4a3bd22ccc63> . }

PREFIX ecrm: <http://erlangen-crm.org/current/>
PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
SELECT ?performance ?work ?composer WHERE { ?work efrbroo:R17_created ?composer . ?performance ecrm:P14_carried_out_by ?composer . ?performance efrbroo:R25_performed ?work . }
